mapper.select:
SELECT id, course_id AS courseId, chapter_id AS chapterId, material_name AS materialName, material_type AS materialType, file_url AS fileUrl, file_size AS fileSize, download_count AS downloadCount, description, sort_order AS sortOrder, created_time AS createdTime FROM course_material
AND course_id = #{q.courseId}
AND chapter_id = #{q.chapterId}
AND material_name LIKE CONCAT('%', #{q.materialName}, '%')
AND material_type = #{q.materialType}
AND created_time BETWEEN #{q.beginTime} AND #{q.endTime}
ORDER BY sort_order ASC, created_time DESC

